import React, { useState, useEffect } from 'react';
import { Routes, Route, Link } from 'react-router-dom';
import Login from './authentication/Login';
import Register from './authentication/register';
import Dashboard from './components/Dashboard';
import UserProfile from './components/UserProfile';
import ProductList from './components/ProductList';
import ShoppingCart from './components/ShoppingCart';
import SearchBar from './components/SearchBar';
import AdminPanel from './components/AdminPanel';
import ErrorBoundary from './components/ErrorBoundary';
import NotificationCenter from './components/NotificationCenter'; // ✅ NEW: Integrated Real-Time Notification Banner
import { AppProvider, useAppContext } from './context/AppContext';
import OrderHistory from './components/OrderHistory';
import { fetchUserCartFromServer, syncUserCartToServer } from './utils/api';
import './styles/App.css';

function App() {
  const [user, setUser] = useState(null);
  const [cart, setCart] = useState([]);
  const [theme, setTheme] = useState("light");

  useEffect(() => {
    const savedUser = localStorage.getItem("currentUser");
    if (savedUser) {
      try {
        setUser(JSON.parse(savedUser));
      } catch (e) {
        console.error(e);
      }
    }
  }, []);

  useEffect(() => {
    console.log("Page viewed:", window.location.pathname);
  }, []);

  function handleLogin(userData) {
    setUser(userData);
    localStorage.setItem("currentUser", JSON.stringify(userData));
  }

  function handleLogout() {
    setUser(null);
    localStorage.removeItem("currentUser");
  }

  // Fetch cart automatically on user login
  useEffect(() => {
    if (user) {
      fetchUserCartFromServer(user.name).then(cloudCart => {
        if (cloudCart && cloudCart.items) {
          setCart(cloudCart.items);
        }
      });
    } else {
      setCart([]);
    }
  }, [user]);

  // ==========================================
  // CORE CART STATE MANIPULATION FUNCTIONS
  // ==========================================

  // 1. ADD item to cart or increment its quantity
  function addToCart(item) {
    setCart(prevCart => {
      const existingItem = prevCart.find(i => i.id === item.id);
      let updatedCart;

      if (existingItem) {
        updatedCart = prevCart.map(i =>
          i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
        );
      } else {
        updatedCart = [...prevCart, { ...item, quantity: 1 }];
      }

      if (user) {
        syncUserCartToServer(user.name, updatedCart);
      }
      return updatedCart;
    });
  }

  // 2. ✅ NEW: UPDATE item quantities directly from the ShoppingCart input boxes
  function updateQuantity(id, newQuantity) {
    setCart(prevCart => {
      const updatedCart = prevCart.map(item =>
        item.id === id ? { ...item, quantity: Math.max(1, newQuantity) } : item
      );
      if (user) {
        syncUserCartToServer(user.name, updatedCart);
      }
      return updatedCart;
    });
  }

  // 3. ✅ NEW: REMOVE items completely from the cart array list
  function removeFromCart(id) {
    setCart(prevCart => {
      const updatedCart = prevCart.filter(item => item.id !== id);
      if (user) {
        syncUserCartToServer(user.name, updatedCart);
      }
      return updatedCart;
    });
  }

  function switchTheme(newTheme) {
    setTheme(newTheme);
  }

  return (
    <AppProvider>
      <ErrorBoundary>
        <div className={`app ${theme}`}>
          <nav className="navbar">
            <Link to="/">Home</Link>
            <Link to="/products">Products</Link>
            {/* Display running cart quantity count dynamically inside header */}
            <Link to="/cart">Cart ({cart.reduce((total, item) => total + item.quantity, 0)})</Link>
            <Link to="/search">Search</Link>
            {user ? (
              <>
                <Link to="/dashboard">Dashboard</Link>
                <Link to={`/profile/${user.id || "me"}`}>Profile</Link>
                <button onClick={handleLogout} style={{ marginLeft: "10px", cursor: "pointer" }}>Logout</button>
                {user.role === "admin" && <Link to="/admin" style={{ marginLeft: "10px", color: "#dc3545", fontWeight: "bold" }}>Admin</Link>}
              </>
            ) : (
              <Link to="/login">Login</Link>
            )}
          </nav>

          <main>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={<Login onLogin={handleLogin} />} />
              <Route path="/register" element={<Register />} />
              <Route path="/dashboard" element={<Dashboard user={user} />} />
              <Route path="/profile/:id" element={<UserProfile />} />
              <Route path="/products" element={<ProductList addToCart={addToCart} />} />

              <Route path="/cart" element={
                <ShoppingCart
                  cartItems={cart}
                  updateQuantity={updateQuantity}
                  removeFromCart={removeFromCart}
                />
              } />

              <Route path="/search" element={<SearchBar addToCart={addToCart} />} />
              <Route path="/orders" element={<OrderHistory user={user} />} />

              {/* =======================================================
        🔒 STRICT COMPONENT GUARD FOR MANUALLY TYPED URLS
        ======================================================= */}
              <Route
                path="/admin"
                element={
                  (() => {
                    // Read localStorage directly BEFORE rendering the component
                    const savedUser = localStorage.getItem("currentUser");
                    const activeUser = savedUser ? JSON.parse(savedUser) : null;

                    // Hard check: If no verified admin token exists, block mounting completely!
                    if (
                      !activeUser ||
                      activeUser.role !== "admin" ||
                      !activeUser.token ||
                      !activeUser.token.startsWith("admin-secure-session")
                    ) {
                      // Force return a message or redirect inline instead of opening the workspace
                      return (
                        <div style={{ padding: "50px", textAlign: "center", fontFamily: "sans-serif" }}>
                          <h3 style={{ color: "#dc3545" }}>⛔ Access Denied</h3>
                          <p>Security violation: You do not have permission to view this panel. Redirecting...</p>
                          <button onClick={() => window.location.href = "/login"} style={{ padding: "10px 20px", background: "#007bff", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" }}>
                            Go to Login
                          </button>
                        </div>
                      );
                    }

                    // ONLY mount the workspace if they pass the hard check
                    return <AdminPanel user={user} />;
                  })()
                }
              />
            </Routes>
          </main>

          {/* ✅ NEW: Global listener handles socket streams and shows real-time deal alerts */}
          <NotificationCenter />
        </div>
      </ErrorBoundary>
    </AppProvider>
  );
}

function Home() {
  const [count, setCount] = useState(0);
  const { state = { user: null } } = useAppContext();

  useEffect(() => {
    const timer = setInterval(() => {
      setCount(c => c + 1);
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="home" style={{ padding: "30px", textAlign: "center" }}>
      <h1>Welcome {state?.user?.name ? ", " + state.user.name : ""}!</h1>
      {count > 0 && <p>You have been here for {count} seconds</p>}
    </div>
  );
}

export default App;
